// Listen to allocation changes for a project (requires SDK)
const channel = timeboxing
  .channel('project-allocations')
  .on(
    'postgres_changes',
    {
      event: '*',           // INSERT, UPDATE, DELETE (or pick one)
      schema: 'public',
      table: 'allocations',
      filter: `project_id=eq.${projectId}`
    },
    (payload) => {
      console.log('Change:', payload.eventType, payload.new)
      // payload.new = row after change
      // payload.old = row before change (UPDATE/DELETE only)
    }
  )
  .subscribe()

// Unsubscribe when done
timeboxing.removeChannel(channel)

