import { createClient } from '@supabase/supabase-js'

const timeboxing = createClient(
  'https://api.taimbox.com',
  process.env.SUPABASE_ANON_KEY!,
  {
    global: {
      headers: { Authorization: `Bearer ${process.env.TIMEBOXING_API_TOKEN}` }
    }
  }
)

const { data, error } = await timeboxing
  .from('employees')
  .select('id, name, role')
  .eq('is_active', true)
  .limit(5)

if (error) {
  console.error('Connection error:', error.message)
} else {
  console.log('Connected! Employees:', data)
  // [{ id: "...", name: "Jane Doe", role: "Designer" }, ...]
}

const { data: newEmployee, error } = await timeboxing
  .from('employees')
  .insert({
    name: 'Laura Martinez',
    first_name: 'Laura',
    last_name: 'Martinez',
    email: 'laura@agency.com',
    role: 'Developer',
    default_weekly_capacity: 40,
    work_schedule: {
      monday: 8, tuesday: 8, wednesday: 8,
      thursday: 8, friday: 8, saturday: 0, sunday: 0
    },
    agency_id: process.env.TIMEBOXING_AGENCY_ID
  })
  .select()
  .single()

if (error) {
  console.error('Create failed:', error.message)
} else {
  console.log('Created employee:', newEmployee.id)
}

const { data, error } = await timeboxing
  .from('employees')
  .update({
    default_weekly_capacity: 32,
    work_schedule: {
      monday: 8, tuesday: 8, wednesday: 8,
      thursday: 8, friday: 0, saturday: 0, sunday: 0
    }
  })
  .eq('id', employeeId)
  .select()
  .single()

// Employee now works 32h/week Mon–Thu

const { error } = await timeboxing
  .from('allocations')
  .update({
    hours_actual: 14,
    status: 'completed'
  })
  .eq('id', allocationId)

// Row marked complete with 14 actual hours

const { data: deadline } = await timeboxing
  .from('deadlines')
  .upsert({
    project_id: projectId,
    month: '2026-03',
    employee_hours: {
      [employeeId1]: 40,
      [employeeId2]: 20
    },
    budget_override: 120
  })
  .select()
  .single()

// Goal: 40h + 20h across March

const { data: allocations } = await timeboxing
  .from('allocations')
  .select('project_id, hours_assigned, hours_actual, hours_computed')
  .gte('week_start_date', '2026-02-01')
  .lte('week_start_date', '2026-02-28')

const byProject = {}
allocations?.forEach(a => {
  if (!byProject[a.project_id]) {
    byProject[a.project_id] = { planned: 0, actual: 0, computed: 0 }
  }
  byProject[a.project_id].planned += a.hours_assigned
  byProject[a.project_id].actual += a.hours_actual
  byProject[a.project_id].computed += a.hours_computed
})

console.log('Hours by project:', byProject)

function toCSV(data, headers) {
  const rows = [headers.join(',')]
  data.forEach(row => {
    rows.push(headers.map(h => JSON.stringify(row[h] ?? '')).join(','))
  })
  return rows.join('\n')
}

